import { Question } from "@/lib/types";

export const questions: Question[] = [
    { id: "y1k2-001", topicRef: "y1k2", topicTitle: "Variable Acceleration 01", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["differentiation", "displacement", "velocity"], questionText: "A particle moves along a straight line such that its displacement at time \\(t\\) seconds is given by \\(s = 4t^2 + 3t\\), where \\(s\\) is measured in metres. Find the velocity of the particle at time \\(t\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Differentiate \\(s\\) with respect to \\(t\\) to find the velocity.", workingLatex: "v = \\frac{\\mathrm{d}s}{\\mathrm{d}t} = 8t + 3", explanation: "Apply the power rule to each term: the derivative of \\(4t^2\\) is \\(8t\\) and the derivative of \\(3t\\) is \\(3\\)." }], finalAnswer: "\\(v = 8t + 3\\) m s\\(^{-1}\\)." } },
    { id: "y1k2-002", topicRef: "y1k2", topicTitle: "Variable Acceleration 02", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["differentiation", "velocity", "acceleration"], questionText: "A particle has velocity \\(v = 3t^2 - 12t + 9\\) m s\\(^{-1}\\) at time \\(t\\) seconds. Find the acceleration of the particle at time \\(t\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Differentiate \\(v\\) with respect to \\(t\\) to find the acceleration.", workingLatex: "a = \\frac{\\mathrm{d}v}{\\mathrm{d}t} = 6t - 12", explanation: "Apply the power rule: the derivative of \\(3t^2\\) is \\(6t\\), the derivative of \\(-12t\\) is \\(-12\\), and the constant \\(9\\) differentiates to \\(0\\)." }], finalAnswer: "\\(a = 6t - 12\\) m s\\(^{-2}\\)." } },
    { id: "y1k2-003", topicRef: "y1k2", topicTitle: "Variable Acceleration 03", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["differentiation", "displacement", "velocity", "acceleration"], questionText: "A particle moves along a straight line with displacement \\(s = t^3 - 6t^2 + 9t + 2\\) metres at time \\(t\\) seconds. Find expressions for the velocity \\(v\\) and the acceleration \\(a\\) at time \\(t\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Differentiate \\(s\\) with respect to \\(t\\) to find \\(v\\).", workingLatex: "v = \\frac{\\mathrm{d}s}{\\mathrm{d}t} = 3t^2 - 12t + 9", explanation: "Apply the power rule term by term." }, { stepNumber: 2, description: "Differentiate \\(v\\) with respect to \\(t\\) to find \\(a\\).", workingLatex: "a = \\frac{\\mathrm{d}v}{\\mathrm{d}t} = 6t - 12", explanation: "Differentiate the velocity expression." }], finalAnswer: "\\(v = 3t^2 - 12t + 9\\) m s\\(^{-1}\\), \\(a = 6t - 12\\) m s\\(^{-2}\\)." } },
    { id: "y1k2-004", topicRef: "y1k2", topicTitle: "Variable Acceleration 04", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["differentiation", "velocity", "substitution"], questionText: "A particle has displacement \\(s = 2t^3 - 9t^2 + 12t\\) metres at time \\(t\\) seconds. Find the velocity of the particle when \\(t = 2\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Differentiate \\(s\\) with respect to \\(t\\) to obtain the velocity.", workingLatex: "v = \\frac{\\mathrm{d}s}{\\mathrm{d}t} = 6t^2 - 18t + 12", explanation: "Apply the power rule to each term." }, { stepNumber: 2, description: "Substitute \\(t = 2\\) into the velocity expression.", workingLatex: "v = 6(2)^2 - 18(2) + 12 = 24 - 36 + 12 = 0", explanation: "The particle is instantaneously at rest when \\(t = 2\\)." }], finalAnswer: "\\(v = 0\\) m s\\(^{-1}\\)." } },
    { id: "y1k2-005", topicRef: "y1k2", topicTitle: "Variable Acceleration 05", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["differentiation", "velocity zero", "at rest"], questionText: "A particle moves along a straight line with displacement \\(s = 2t^3 - 9t^2 + 12t\\) metres at time \\(t \\geq 0\\) seconds. Find the times at which the particle is instantaneously at rest.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the velocity by differentiating \\(s\\).", workingLatex: "v = \\frac{\\mathrm{d}s}{\\mathrm{d}t} = 6t^2 - 18t + 12", explanation: "" }, { stepNumber: 2, description: "Set \\(v = 0\\) and solve.", workingLatex: "6t^2 - 18t + 12 = 0", explanation: "The particle is at rest when the velocity is zero." }, { stepNumber: 3, description: "Simplify by dividing through by 6.", workingLatex: "t^2 - 3t + 2 = 0", explanation: "" }, { stepNumber: 4, description: "Factorise and solve.", workingLatex: "(t - 1)(t - 2) = 0 \\implies t = 1 \\text{ or } t = 2", explanation: "Both values are non-negative so both are valid." }], finalAnswer: "The particle is at rest when \\(t = 1\\) s and \\(t = 2\\) s." } },
    { id: "y1k2-006", topicRef: "y1k2", topicTitle: "Variable Acceleration 06", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["differentiation", "acceleration", "substitution"], questionText: "A particle has displacement \\(s = t^4 - 4t^3 + 6\\) metres at time \\(t\\) seconds. Find the acceleration of the particle when \\(t = 3\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Differentiate \\(s\\) to find the velocity.", workingLatex: "v = \\frac{\\mathrm{d}s}{\\mathrm{d}t} = 4t^3 - 12t^2", explanation: "" }, { stepNumber: 2, description: "Differentiate \\(v\\) to find the acceleration.", workingLatex: "a = \\frac{\\mathrm{d}v}{\\mathrm{d}t} = 12t^2 - 24t", explanation: "" }, { stepNumber: 3, description: "Substitute \\(t = 3\\).", workingLatex: "a = 12(3)^2 - 24(3) = 108 - 72 = 36", explanation: "" }], finalAnswer: "\\(a = 36\\) m s\\(^{-2}\\)." } },
    { id: "y1k2-007", topicRef: "y1k2", topicTitle: "Variable Acceleration 07", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["differentiation", "acceleration zero"], questionText: "A particle moves with displacement \\(s = t^3 - 6t^2 + 9t + 2\\) metres at time \\(t\\) seconds. Find the time at which the acceleration of the particle is zero.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the velocity.", workingLatex: "v = \\frac{\\mathrm{d}s}{\\mathrm{d}t} = 3t^2 - 12t + 9", explanation: "" }, { stepNumber: 2, description: "Find the acceleration.", workingLatex: "a = \\frac{\\mathrm{d}v}{\\mathrm{d}t} = 6t - 12", explanation: "" }, { stepNumber: 3, description: "Set \\(a = 0\\) and solve.", workingLatex: "6t - 12 = 0 \\implies t = 2", explanation: "" }], finalAnswer: "The acceleration is zero when \\(t = 2\\) s." } },
    { id: "y1k2-008", topicRef: "y1k2", topicTitle: "Variable Acceleration 08", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Challenge", tags: ["differentiation", "velocity", "displacement", "combined"], questionText: "A particle moves along a straight line with displacement \\(s = 5t^2 - t^3\\) metres at time \\(t \\geq 0\\) seconds. Find the velocity when the acceleration is zero, and determine the displacement of the particle at that instant.", workedSolution: { steps: [{ stepNumber: 1, description: "Differentiate to find the velocity.", workingLatex: "v = \\frac{\\mathrm{d}s}{\\mathrm{d}t} = 10t - 3t^2", explanation: "" }, { stepNumber: 2, description: "Differentiate again to find the acceleration.", workingLatex: "a = \\frac{\\mathrm{d}v}{\\mathrm{d}t} = 10 - 6t", explanation: "" }, { stepNumber: 3, description: "Set \\(a = 0\\) and solve for \\(t\\).", workingLatex: "10 - 6t = 0 \\implies t = \\frac{5}{3}", explanation: "" }, { stepNumber: 4, description: "Find the velocity at \\(t = \\frac{5}{3}\\).", workingLatex: "v = 10\\left(\\frac{5}{3}\\right) - 3\\left(\\frac{5}{3}\\right)^2 = \\frac{50}{3} - 3 \\cdot \\frac{25}{9} = \\frac{50}{3} - \\frac{25}{3} = \\frac{25}{3}", explanation: "" }, { stepNumber: 5, description: "Find the displacement at \\(t = \\frac{5}{3}\\).", workingLatex: "s = 5\\left(\\frac{5}{3}\\right)^2 - \\left(\\frac{5}{3}\\right)^3 = \\frac{125}{9} - \\frac{125}{27} = \\frac{375 - 125}{27} = \\frac{250}{27}", explanation: "" }], finalAnswer: "When \\(a = 0\\), \\(v = \\frac{25}{3}\\) m s\\(^{-1}\\) and \\(s = \\frac{250}{27}\\) m." } },
    { id: "y1k2-009", topicRef: "y1k2", topicTitle: "Variable Acceleration 09", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["integration", "acceleration", "velocity", "initial conditions"], questionText: "A particle moves along a straight line with acceleration \\(a = 6t - 4\\) m s\\(^{-2}\\) at time \\(t\\) seconds. Given that the initial velocity is \\(5\\) m s\\(^{-1}\\), find an expression for the velocity \\(v\\) at time \\(t\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Integrate the acceleration to find the velocity.", workingLatex: "v = \\int (6t - 4)\\, \\mathrm{d}t = 3t^2 - 4t + c", explanation: "Remember to include the constant of integration." }, { stepNumber: 2, description: "Use the initial condition \\(v = 5\\) when \\(t = 0\\) to find \\(c\\).", workingLatex: "5 = 3(0)^2 - 4(0) + c \\implies c = 5", explanation: "" }, { stepNumber: 3, description: "Write the complete expression.", workingLatex: "v = 3t^2 - 4t + 5", explanation: "" }], finalAnswer: "\\(v = 3t^2 - 4t + 5\\) m s\\(^{-1}\\)." } },
    { id: "y1k2-010", topicRef: "y1k2", topicTitle: "Variable Acceleration 10", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["integration", "velocity", "displacement", "initial conditions"], questionText: "A particle has velocity \\(v = 4t - t^2\\) m s\\(^{-1}\\) at time \\(t\\) seconds. Given that the particle starts at the origin, find an expression for the displacement \\(s\\) at time \\(t\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Integrate the velocity to find the displacement.", workingLatex: "s = \\int (4t - t^2)\\, \\mathrm{d}t = 2t^2 - \\frac{t^3}{3} + c", explanation: "" }, { stepNumber: 2, description: "Use the initial condition \\(s = 0\\) when \\(t = 0\\).", workingLatex: "0 = 0 - 0 + c \\implies c = 0", explanation: "The particle starts at the origin." }, { stepNumber: 3, description: "Write the complete expression.", workingLatex: "s = 2t^2 - \\frac{t^3}{3}", explanation: "" }], finalAnswer: "\\(s = 2t^2 - \\frac{t^3}{3}\\) m." } },
    { id: "y1k2-011", topicRef: "y1k2", topicTitle: "Variable Acceleration 11", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["integration", "acceleration", "velocity", "specific time"], questionText: "A particle moves with acceleration \\(a = 10 - 6t\\) m s\\(^{-2}\\) at time \\(t\\) seconds. When \\(t = 0\\) the velocity is \\(2\\) m s\\(^{-1}\\). Find the velocity when \\(t = 3\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Integrate to find the velocity.", workingLatex: "v = \\int (10 - 6t)\\, \\mathrm{d}t = 10t - 3t^2 + c", explanation: "" }, { stepNumber: 2, description: "Use the initial condition \\(v = 2\\) when \\(t = 0\\).", workingLatex: "2 = 0 - 0 + c \\implies c = 2", explanation: "" }, { stepNumber: 3, description: "So \\(v = 10t - 3t^2 + 2\\). Substitute \\(t = 3\\).", workingLatex: "v = 10(3) - 3(3)^2 + 2 = 30 - 27 + 2 = 5", explanation: "" }], finalAnswer: "\\(v = 5\\) m s\\(^{-1}\\)." } },
    { id: "y1k2-012", topicRef: "y1k2", topicTitle: "Variable Acceleration 12", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Standard", tags: ["integration", "velocity", "displacement", "specific time"], questionText: "A particle moves along a straight line with velocity \\(v = 3t^2 - 10t + 7\\) m s\\(^{-1}\\) at time \\(t\\) seconds. When \\(t = 0\\) the displacement is \\(4\\) m from the origin. Find the displacement when \\(t = 3\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Integrate the velocity to find the displacement.", workingLatex: "s = \\int (3t^2 - 10t + 7)\\, \\mathrm{d}t = t^3 - 5t^2 + 7t + c", explanation: "" }, { stepNumber: 2, description: "Use the initial condition \\(s = 4\\) when \\(t = 0\\).", workingLatex: "4 = 0 - 0 + 0 + c \\implies c = 4", explanation: "" }, { stepNumber: 3, description: "So \\(s = t^3 - 5t^2 + 7t + 4\\). Substitute \\(t = 3\\).", workingLatex: "s = (3)^3 - 5(3)^2 + 7(3) + 4 = 27 - 45 + 21 + 4 = 7", explanation: "" }], finalAnswer: "\\(s = 7\\) m." } },
    { id: "y1k2-013", topicRef: "y1k2", topicTitle: "Variable Acceleration 13", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["integration", "definite", "displacement", "interval"], questionText: "A particle has velocity \\(v = 6t - 2\\) m s\\(^{-1}\\) at time \\(t\\) seconds. Find the displacement of the particle between \\(t = 1\\) and \\(t = 4\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Use definite integration to find the displacement over the interval.", workingLatex: "s = \\int_1^4 (6t - 2)\\, \\mathrm{d}t", explanation: "" }, { stepNumber: 2, description: "Integrate.", workingLatex: "s = \\left[3t^2 - 2t\\right]_1^4", explanation: "" }, { stepNumber: 3, description: "Evaluate at the limits.", workingLatex: "s = (3(16) - 8) - (3(1) - 2) = (48 - 8) - (3 - 2) = 40 - 1 = 39", explanation: "" }], finalAnswer: "The displacement is \\(39\\) m." } },
    { id: "y1k2-014", topicRef: "y1k2", topicTitle: "Variable Acceleration 14", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Standard", tags: ["integration", "acceleration", "velocity", "displacement", "two stages"], questionText: "A particle starts from rest and moves with acceleration \\(a = 12t - 6\\) m s\\(^{-2}\\). Find an expression for the displacement \\(s\\) at time \\(t\\), given that \\(s = 0\\) when \\(t = 0\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Integrate acceleration to find velocity.", workingLatex: "v = \\int (12t - 6)\\, \\mathrm{d}t = 6t^2 - 6t + c_1", explanation: "" }, { stepNumber: 2, description: "The particle starts from rest, so \\(v = 0\\) when \\(t = 0\\).", workingLatex: "0 = 0 - 0 + c_1 \\implies c_1 = 0", explanation: "So \\(v = 6t^2 - 6t\\)." }, { stepNumber: 3, description: "Integrate velocity to find displacement.", workingLatex: "s = \\int (6t^2 - 6t)\\, \\mathrm{d}t = 2t^3 - 3t^2 + c_2", explanation: "" }, { stepNumber: 4, description: "Use \\(s = 0\\) when \\(t = 0\\).", workingLatex: "0 = 0 - 0 + c_2 \\implies c_2 = 0", explanation: "" }], finalAnswer: "\\(s = 2t^3 - 3t^2\\) m." } },
    { id: "y1k2-015", topicRef: "y1k2", topicTitle: "Variable Acceleration 15", yearCreated: 2026, examStyle: false, marks: 6, difficulty: "Challenge", tags: ["integration", "acceleration", "velocity", "non-zero initial"], questionText: "At time \\(t = 0\\), a particle passes through a point \\(O\\) with velocity \\(8\\) m s\\(^{-1}\\). The acceleration of the particle is \\(a = 6 - 4t\\) m s\\(^{-2}\\). Find the displacement of the particle from \\(O\\) when the particle is next instantaneously at rest.", workedSolution: { steps: [{ stepNumber: 1, description: "Integrate to find velocity.", workingLatex: "v = \\int (6 - 4t)\\, \\mathrm{d}t = 6t - 2t^2 + c", explanation: "" }, { stepNumber: 2, description: "Use \\(v = 8\\) when \\(t = 0\\).", workingLatex: "8 = 0 - 0 + c \\implies c = 8 \\quad \\Rightarrow \\quad v = 6t - 2t^2 + 8", explanation: "" }, { stepNumber: 3, description: "Set \\(v = 0\\) to find when the particle is next at rest.", workingLatex: "6t - 2t^2 + 8 = 0 \\implies 2t^2 - 6t - 8 = 0 \\implies t^2 - 3t - 4 = 0", explanation: "" }, { stepNumber: 4, description: "Factorise.", workingLatex: "(t - 4)(t + 1) = 0 \\implies t = 4 \\text{ (since } t \\geq 0\\text{)}", explanation: "Reject \\(t = -1\\) as time must be non-negative." }, { stepNumber: 5, description: "Integrate velocity to find displacement, using \\(s = 0\\) when \\(t = 0\\).", workingLatex: "s = \\int (6t - 2t^2 + 8)\\, \\mathrm{d}t = 3t^2 - \\frac{2t^3}{3} + 8t + c_2", explanation: "\\(s = 0\\) when \\(t = 0\\) gives \\(c_2 = 0\\)." }, { stepNumber: 6, description: "Substitute \\(t = 4\\).", workingLatex: "s = 3(16) - \\frac{2(64)}{3} + 8(4) = 48 - \\frac{128}{3} + 32 = 80 - \\frac{128}{3} = \\frac{240 - 128}{3} = \\frac{112}{3}", explanation: "" }], finalAnswer: "The displacement from \\(O\\) is \\(\\frac{112}{3}\\) m." } },
    { id: "y1k2-016", topicRef: "y1k2", topicTitle: "Variable Acceleration 16", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Challenge", tags: ["integration", "definite", "displacement", "velocity"], questionText: "A particle has velocity \\(v = t^2 - 6t + 8\\) m s\\(^{-1}\\) at time \\(t\\) seconds. Find the displacement of the particle between \\(t = 0\\) and \\(t = 5\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Set up the definite integral.", workingLatex: "s = \\int_0^5 (t^2 - 6t + 8)\\, \\mathrm{d}t", explanation: "" }, { stepNumber: 2, description: "Integrate.", workingLatex: "s = \\left[\\frac{t^3}{3} - 3t^2 + 8t\\right]_0^5", explanation: "" }, { stepNumber: 3, description: "Evaluate at the upper limit.", workingLatex: "\\frac{125}{3} - 75 + 40 = \\frac{125}{3} - 35 = \\frac{125 - 105}{3} = \\frac{20}{3}", explanation: "" }, { stepNumber: 4, description: "Evaluate at the lower limit.", workingLatex: "0 - 0 + 0 = 0", explanation: "" }, { stepNumber: 5, description: "Subtract.", workingLatex: "s = \\frac{20}{3} - 0 = \\frac{20}{3}", explanation: "" }], finalAnswer: "The displacement is \\(\\frac{20}{3}\\) m." } },
    { id: "y1k2-017", topicRef: "y1k2", topicTitle: "Variable Acceleration 17", yearCreated: 2026, examStyle: true, marks: 8, difficulty: "Standard", tags: ["differentiation", "velocity", "at rest", "displacement", "multi-part"], questionText: "A particle \\(P\\) moves along a straight line. At time \\(t\\) seconds (\\(t \\geq 0\\)), the displacement of \\(P\\) from a fixed point \\(O\\) on the line is \\(s\\) metres, where \\(s = t^3 - 5t^2 + 3t + 5\\). (a) Find an expression for the velocity of \\(P\\) at time \\(t\\). (b) Find the times when \\(P\\) is instantaneously at rest. (c) Find the acceleration of \\(P\\) at each of these times.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Differentiate \\(s\\) to find the velocity.", workingLatex: "v = \\frac{\\mathrm{d}s}{\\mathrm{d}t} = 3t^2 - 10t + 3", explanation: "" }, { stepNumber: 2, description: "(b) Set \\(v = 0\\) and solve.", workingLatex: "3t^2 - 10t + 3 = 0", explanation: "" }, { stepNumber: 3, description: "Use the quadratic formula.", workingLatex: "t = \\frac{10 \\pm \\sqrt{100 - 36}}{6} = \\frac{10 \\pm 8}{6}", explanation: "" }, { stepNumber: 4, description: "Find both solutions.", workingLatex: "t = \\frac{18}{6} = 3 \\quad \\text{or} \\quad t = \\frac{2}{6} = \\frac{1}{3}", explanation: "" }, { stepNumber: 5, description: "(c) Find the acceleration.", workingLatex: "a = \\frac{\\mathrm{d}v}{\\mathrm{d}t} = 6t - 10", explanation: "" }, { stepNumber: 6, description: "Substitute each time value.", workingLatex: "\\text{When } t = \\tfrac{1}{3}: \\; a = 6\\left(\\tfrac{1}{3}\\right) - 10 = 2 - 10 = -8 \\qquad \\text{When } t = 3: \\; a = 6(3) - 10 = 8", explanation: "" }], finalAnswer: "(a) \\(v = 3t^2 - 10t + 3\\). (b) \\(t = \\frac{1}{3}\\) s and \\(t = 3\\) s. (c) \\(a = -8\\) m s\\(^{-2}\\) when \\(t = \\frac{1}{3}\\) and \\(a = 8\\) m s\\(^{-2}\\) when \\(t = 3\\)." } },
    { id: "y1k2-018", topicRef: "y1k2", topicTitle: "Variable Acceleration 18", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["differentiation", "maximum displacement", "second derivative test"], questionText: "A particle moves along a straight line with displacement \\(s = 12t + 3t^2 - 2t^3\\) metres at time \\(t \\geq 0\\) seconds. Show that the maximum displacement of the particle from its initial position is \\(20\\) m, and find the time at which this maximum occurs.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the velocity.", workingLatex: "v = \\frac{\\mathrm{d}s}{\\mathrm{d}t} = 12 + 6t - 6t^2", explanation: "" }, { stepNumber: 2, description: "Set \\(v = 0\\) and solve.", workingLatex: "12 + 6t - 6t^2 = 0 \\implies 6t^2 - 6t - 12 = 0 \\implies t^2 - t - 2 = 0", explanation: "" }, { stepNumber: 3, description: "Factorise.", workingLatex: "(t - 2)(t + 1) = 0 \\implies t = 2 \\text{ (rejecting } t = -1\\text{)}", explanation: "" }, { stepNumber: 4, description: "Find the acceleration to confirm this is a maximum.", workingLatex: "a = \\frac{\\mathrm{d}v}{\\mathrm{d}t} = 6 - 12t", explanation: "" }, { stepNumber: 5, description: "Evaluate the acceleration at \\(t = 2\\).", workingLatex: "a(2) = 6 - 24 = -18 < 0", explanation: "Since the second derivative of \\(s\\) is negative at \\(t = 2\\), this confirms a maximum." }, { stepNumber: 6, description: "Find the displacement at \\(t = 2\\).", workingLatex: "s(2) = 12(2) + 3(4) - 2(8) = 24 + 12 - 16 = 20", explanation: "" }, { stepNumber: 7, description: "Note that \\(s(0) = 0\\), so the displacement from the initial position is \\(20 - 0 = 20\\) m, as required.", workingLatex: "s(0) = 0 \\implies \\text{maximum displacement from initial position} = 20 - 0 = 20 \\text{ m}", explanation: "" }], finalAnswer: "The maximum displacement from the initial position is \\(20\\) m, occurring at \\(t = 2\\) s." } },
    { id: "y1k2-019", topicRef: "y1k2", topicTitle: "Variable Acceleration 19", yearCreated: 2026, examStyle: true, marks: 9, difficulty: "Challenge", tags: ["integration", "distance", "displacement", "direction change"], questionText: "A particle moves along a straight line with velocity \\(v = t^2 - 4t + 3\\) m s\\(^{-1}\\) at time \\(t \\geq 0\\) seconds. Find the total distance travelled by the particle between \\(t = 0\\) and \\(t = 4\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Find when \\(v = 0\\) to identify direction changes.", workingLatex: "t^2 - 4t + 3 = 0 \\implies (t - 1)(t - 3) = 0 \\implies t = 1 \\text{ or } t = 3", explanation: "The particle changes direction at \\(t = 1\\) and \\(t = 3\\)." }, { stepNumber: 2, description: "Find the displacement from \\(t = 0\\) to \\(t = 1\\).", workingLatex: "\\int_0^1 (t^2 - 4t + 3)\\, \\mathrm{d}t = \\left[\\frac{t^3}{3} - 2t^2 + 3t\\right]_0^1 = \\frac{1}{3} - 2 + 3 = \\frac{4}{3}", explanation: "Positive, so the particle moves in the positive direction." }, { stepNumber: 3, description: "Find the displacement from \\(t = 1\\) to \\(t = 3\\).", workingLatex: "\\int_1^3 (t^2 - 4t + 3)\\, \\mathrm{d}t = \\left[\\frac{t^3}{3} - 2t^2 + 3t\\right]_1^3 = (9 - 18 + 9) - \\left(\\frac{1}{3} - 2 + 3\\right) = 0 - \\frac{4}{3} = -\\frac{4}{3}", explanation: "Negative, so the particle moves in the negative direction during this interval." }, { stepNumber: 4, description: "Find the displacement from \\(t = 3\\) to \\(t = 4\\).", workingLatex: "\\int_3^4 (t^2 - 4t + 3)\\, \\mathrm{d}t = \\left[\\frac{t^3}{3} - 2t^2 + 3t\\right]_3^4 = \\left(\\frac{64}{3} - 32 + 12\\right) - 0 = \\frac{64}{3} - 20 = \\frac{4}{3}", explanation: "Positive again." }, { stepNumber: 5, description: "Total distance is the sum of the absolute values.", workingLatex: "\\text{Distance} = \\left|\\frac{4}{3}\\right| + \\left|-\\frac{4}{3}\\right| + \\left|\\frac{4}{3}\\right| = \\frac{4}{3} + \\frac{4}{3} + \\frac{4}{3} = 4", explanation: "Take the magnitude of each part since distance is always positive." }], finalAnswer: "The total distance travelled is \\(4\\) m." } },
    { id: "y1k2-020", topicRef: "y1k2", topicTitle: "Variable Acceleration 20", yearCreated: 2026, examStyle: true, marks: 10, difficulty: "Challenge", tags: ["differentiation", "integration", "show that", "algebraic", "unknown coefficient", "distance"], questionText: "A particle moves along a straight line. At time \\(t\\) seconds (\\(t \\geq 0\\)), the displacement of the particle from a fixed point \\(O\\) is given by \\(s = pt^3 - 18t^2 + qt\\), where \\(p\\) and \\(q\\) are positive constants. The particle is instantaneously at rest when \\(t = 1\\) and when \\(t = 3\\). (a) Show that \\(p = 3\\) and find the value of \\(q\\). (b) Find the acceleration of the particle when \\(t = 2\\). (c) Find the total distance travelled by the particle between \\(t = 0\\) and \\(t = 4\\).", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Find the velocity by differentiating \\(s\\).", workingLatex: "v = \\frac{\\mathrm{d}s}{\\mathrm{d}t} = 3pt^2 - 36t + q", explanation: "" }, { stepNumber: 2, description: "Use \\(v = 0\\) when \\(t = 1\\).", workingLatex: "3p(1)^2 - 36(1) + q = 0 \\implies 3p + q = 36 \\quad \\cdots (1)", explanation: "" }, { stepNumber: 3, description: "Use \\(v = 0\\) when \\(t = 3\\).", workingLatex: "3p(3)^2 - 36(3) + q = 0 \\implies 27p + q = 108 \\quad \\cdots (2)", explanation: "" }, { stepNumber: 4, description: "Subtract equation (1) from equation (2).", workingLatex: "24p = 72 \\implies p = 3", explanation: "This shows \\(p = 3\\) as required." }, { stepNumber: 5, description: "Substitute \\(p = 3\\) into equation (1) to find \\(q\\).", workingLatex: "9 + q = 36 \\implies q = 27", explanation: "" }, { stepNumber: 6, description: "(b) Find the acceleration.", workingLatex: "a = \\frac{\\mathrm{d}v}{\\mathrm{d}t} = 18t - 36", explanation: "Using \\(v = 9t^2 - 36t + 27\\)." }, { stepNumber: 7, description: "Substitute \\(t = 2\\).", workingLatex: "a = 18(2) - 36 = 36 - 36 = 0", explanation: "" }, { stepNumber: 8, description: "(c) The velocity factorises as \\(v = 9(t^2 - 4t + 3) = 9(t - 1)(t - 3)\\). The particle is at rest at \\(t = 1\\) and \\(t = 3\\).", workingLatex: "v > 0 \\text{ for } 0 < t < 1, \\quad v < 0 \\text{ for } 1 < t < 3, \\quad v > 0 \\text{ for } t > 3", explanation: "The particle changes direction at \\(t = 1\\) and \\(t = 3\\)." }, { stepNumber: 9, description: "Find the displacement at key times using \\(s = 3t^3 - 18t^2 + 27t\\).", workingLatex: "s(0) = 0, \\quad s(1) = 3 - 18 + 27 = 12, \\quad s(3) = 81 - 162 + 81 = 0, \\quad s(4) = 192 - 288 + 108 = 12", explanation: "" }, { stepNumber: 10, description: "Calculate the total distance.", workingLatex: "\\text{Distance} = |s(1) - s(0)| + |s(3) - s(1)| + |s(4) - s(3)| = |12| + |-12| + |12| = 36", explanation: "The particle travels 12 m forward, then 12 m back, then 12 m forward again." }], finalAnswer: "(a) \\(p = 3\\) and \\(q = 27\\). (b) \\(a = 0\\) m s\\(^{-2}\\). (c) The total distance is \\(36\\) m." } },
    { id: "y1k2-021", topicRef: "y1k2", topicTitle: "Variable Acceleration 21", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Foundation", tags: ["integration", "acceleration", "velocity", "displacement", "two integrations", "initial conditions"], questionText: "A particle moves along a straight line with acceleration \\(a = 4t - 6\\) m s\\(^{-2}\\) at time \\(t\\) seconds. When \\(t = 0\\), the velocity is \\(3\\) m s\\(^{-1}\\) and the displacement from the origin is \\(0\\). Find expressions for the velocity and displacement at time \\(t\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Integrate the acceleration to find the velocity.", workingLatex: "v = \\int (4t - 6)\\,\\mathrm{d}t = 2t^2 - 6t + c_1", explanation: "" }, { stepNumber: 2, description: "Use the initial condition \\(v = 3\\) when \\(t = 0\\).", workingLatex: "3 = 0 - 0 + c_1 \\implies c_1 = 3 \\quad \\Rightarrow \\quad v = 2t^2 - 6t + 3", explanation: "" }, { stepNumber: 3, description: "Integrate the velocity to find the displacement.", workingLatex: "s = \\int (2t^2 - 6t + 3)\\,\\mathrm{d}t = \\frac{2t^3}{3} - 3t^2 + 3t + c_2", explanation: "" }, { stepNumber: 4, description: "Use the initial condition \\(s = 0\\) when \\(t = 0\\).", workingLatex: "0 = 0 - 0 + 0 + c_2 \\implies c_2 = 0", explanation: "" }], finalAnswer: "\\(v = 2t^2 - 6t + 3\\) m s\\(^{-1}\\), \\(s = \\frac{2t^3}{3} - 3t^2 + 3t\\) m." } },
    { id: "y1k2-022", topicRef: "y1k2", topicTitle: "Variable Acceleration 22", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Foundation", tags: ["integration", "acceleration", "velocity", "displacement", "two integrations", "non-zero initial"], questionText: "A particle has acceleration \\(a = 6t\\) m s\\(^{-2}\\) at time \\(t\\) seconds. When \\(t = 0\\), the velocity is \\(4\\) m s\\(^{-1}\\) and the displacement from a fixed point \\(O\\) is \\(2\\) m. Find the displacement when \\(t = 3\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Integrate the acceleration to find the velocity.", workingLatex: "v = \\int 6t\\,\\mathrm{d}t = 3t^2 + c_1", explanation: "" }, { stepNumber: 2, description: "Use \\(v = 4\\) when \\(t = 0\\).", workingLatex: "4 = 0 + c_1 \\implies c_1 = 4 \\quad \\Rightarrow \\quad v = 3t^2 + 4", explanation: "" }, { stepNumber: 3, description: "Integrate the velocity to find the displacement.", workingLatex: "s = \\int (3t^2 + 4)\\,\\mathrm{d}t = t^3 + 4t + c_2", explanation: "" }, { stepNumber: 4, description: "Use \\(s = 2\\) when \\(t = 0\\).", workingLatex: "2 = 0 + 0 + c_2 \\implies c_2 = 2 \\quad \\Rightarrow \\quad s = t^3 + 4t + 2", explanation: "" }, { stepNumber: 5, description: "Substitute \\(t = 3\\).", workingLatex: "s = 27 + 12 + 2 = 41", explanation: "" }], finalAnswer: "\\(s = 41\\) m." } },
    { id: "y1k2-023", topicRef: "y1k2", topicTitle: "Variable Acceleration 23", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Foundation", tags: ["definite integral", "displacement", "velocity", "interval"], questionText: "A particle has velocity \\(v = 3t^2 - 2t\\) m s\\(^{-1}\\) at time \\(t\\) seconds. Use a definite integral to find the displacement of the particle between \\(t = 1\\) and \\(t = 3\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Set up the definite integral.", workingLatex: "s = \\int_1^3 (3t^2 - 2t)\\,\\mathrm{d}t", explanation: "" }, { stepNumber: 2, description: "Integrate.", workingLatex: "s = \\left[t^3 - t^2\\right]_1^3", explanation: "" }, { stepNumber: 3, description: "Evaluate at the limits.", workingLatex: "s = (27 - 9) - (1 - 1) = 18 - 0 = 18", explanation: "" }], finalAnswer: "The displacement between \\(t = 1\\) and \\(t = 3\\) is \\(18\\) m." } },
    { id: "y1k2-024", topicRef: "y1k2", topicTitle: "Variable Acceleration 24", yearCreated: 2026, examStyle: false, marks: 6, difficulty: "Foundation", tags: ["integration", "distance", "displacement", "direction change", "absolute value"], questionText: "A particle has velocity \\(v = 6t - t^2 - 8\\) m s\\(^{-1}\\) at time \\(t \\geq 0\\) seconds. Find the total distance travelled by the particle between \\(t = 0\\) and \\(t = 6\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Find when \\(v = 0\\) to identify direction changes.", workingLatex: "6t - t^2 - 8 = 0 \\implies t^2 - 6t + 8 = 0 \\implies (t - 2)(t - 4) = 0 \\implies t = 2 \\text{ or } t = 4", explanation: "" }, { stepNumber: 2, description: "Find the displacement from \\(t = 0\\) to \\(t = 2\\). Check sign: \\(v(1) = 6 - 1 - 8 = -3 < 0\\), so the particle moves in the negative direction.", workingLatex: "\\int_0^2 (6t - t^2 - 8)\\,\\mathrm{d}t = \\left[3t^2 - \\frac{t^3}{3} - 8t\\right]_0^2 = 12 - \\frac{8}{3} - 16 = -4 - \\frac{8}{3} = -\\frac{20}{3}", explanation: "" }, { stepNumber: 3, description: "Find the displacement from \\(t = 2\\) to \\(t = 4\\). Check sign: \\(v(3) = 18 - 9 - 8 = 1 > 0\\), so positive direction.", workingLatex: "\\int_2^4 (6t - t^2 - 8)\\,\\mathrm{d}t = \\left[3t^2 - \\frac{t^3}{3} - 8t\\right]_2^4 = \\left(48 - \\frac{64}{3} - 32\\right) - \\left(12 - \\frac{8}{3} - 16\\right) = \\frac{-16}{3} - \\frac{-20}{3} = \\frac{4}{3}", explanation: "" }, { stepNumber: 4, description: "Find the displacement from \\(t = 4\\) to \\(t = 6\\). Check sign: \\(v(5) = 30 - 25 - 8 = -3 < 0\\), so negative direction.", workingLatex: "\\int_4^6 (6t - t^2 - 8)\\,\\mathrm{d}t = \\left[3t^2 - \\frac{t^3}{3} - 8t\\right]_4^6 = \\left(108 - 72 - 48\\right) - \\left(48 - \\frac{64}{3} - 32\\right) = -12 - \\frac{-16}{3} = -12 + \\frac{16}{3} = -\\frac{20}{3}", explanation: "" }, { stepNumber: 5, description: "Total distance is the sum of the absolute values.", workingLatex: "\\text{Distance} = \\frac{20}{3} + \\frac{4}{3} + \\frac{20}{3} = \\frac{44}{3}", explanation: "" }], finalAnswer: "The total distance travelled is \\(\\frac{44}{3}\\) m, or \\(14\\frac{2}{3}\\) m." } },
    { id: "y1k2-025", topicRef: "y1k2", topicTitle: "Variable Acceleration 25", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Standard", tags: ["integration", "fractional powers", "velocity", "displacement"], questionText: "A particle has velocity \\(v = 4t^{1/2} - 2\\) m s\\(^{-1}\\) at time \\(t > 0\\) seconds. Given that \\(s = 0\\) when \\(t = 1\\), find an expression for the displacement \\(s\\) at time \\(t\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Integrate the velocity to find the displacement.", workingLatex: "s = \\int (4t^{1/2} - 2)\\,\\mathrm{d}t = 4 \\cdot \\frac{t^{3/2}}{3/2} - 2t + c = \\frac{8}{3}t^{3/2} - 2t + c", explanation: "Recall that \\(\\int t^{n}\\,\\mathrm{d}t = \\frac{t^{n+1}}{n+1} + c\\) for \\(n \\neq -1\\)." }, { stepNumber: 2, description: "Use the condition \\(s = 0\\) when \\(t = 1\\).", workingLatex: "0 = \\frac{8}{3}(1) - 2(1) + c = \\frac{8}{3} - 2 + c = \\frac{2}{3} + c \\implies c = -\\frac{2}{3}", explanation: "" }, { stepNumber: 3, description: "Write the complete expression.", workingLatex: "s = \\frac{8}{3}t^{3/2} - 2t - \\frac{2}{3}", explanation: "" }], finalAnswer: "\\(s = \\frac{8}{3}t^{3/2} - 2t - \\frac{2}{3}\\) m." } },
    { id: "y1k2-026", topicRef: "y1k2", topicTitle: "Variable Acceleration 26", yearCreated: 2026, examStyle: false, marks: 6, difficulty: "Standard", tags: ["integration", "fractional powers", "acceleration", "velocity", "displacement", "two integrations"], questionText: "A particle has acceleration \\(a = 3t^{-1/2}\\) m s\\(^{-2}\\) for \\(t > 0\\). When \\(t = 4\\), the velocity is \\(15\\) m s\\(^{-1}\\) and the displacement from the origin is \\(0\\). Find the displacement when \\(t = 9\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Integrate the acceleration to find the velocity.", workingLatex: "v = \\int 3t^{-1/2}\\,\\mathrm{d}t = 3 \\cdot \\frac{t^{1/2}}{1/2} + c_1 = 6t^{1/2} + c_1", explanation: "" }, { stepNumber: 2, description: "Use \\(v = 15\\) when \\(t = 4\\).", workingLatex: "15 = 6(2) + c_1 = 12 + c_1 \\implies c_1 = 3 \\quad \\Rightarrow \\quad v = 6t^{1/2} + 3", explanation: "" }, { stepNumber: 3, description: "Integrate the velocity to find the displacement.", workingLatex: "s = \\int (6t^{1/2} + 3)\\,\\mathrm{d}t = 6 \\cdot \\frac{t^{3/2}}{3/2} + 3t + c_2 = 4t^{3/2} + 3t + c_2", explanation: "" }, { stepNumber: 4, description: "Use \\(s = 0\\) when \\(t = 4\\).", workingLatex: "0 = 4(8) + 12 + c_2 = 44 + c_2 \\implies c_2 = -44 \\quad \\Rightarrow \\quad s = 4t^{3/2} + 3t - 44", explanation: "" }, { stepNumber: 5, description: "Substitute \\(t = 9\\).", workingLatex: "s = 4(27) + 27 - 44 = 108 + 27 - 44 = 91", explanation: "" }], finalAnswer: "\\(s = 91\\) m." } },
    { id: "y1k2-027", topicRef: "y1k2", topicTitle: "Variable Acceleration 27", yearCreated: 2026, examStyle: true, marks: 8, difficulty: "Standard", tags: ["unknown coefficients", "simultaneous equations", "velocity", "acceleration", "at rest"], questionText: "A particle \\(P\\) moves along the \\(x\\)-axis. At time \\(t\\) seconds, the velocity of \\(P\\) is \\(v\\) m s\\(^{-1}\\) where \\(v = kt^2 - 12t + c\\). When \\(t = 0\\), \\(v = 5\\) and when \\(t = 2\\), \\(v = 1\\). (a) Find the values of \\(k\\) and \\(c\\). (b) Find the acceleration when \\(t = 3\\). (c) Find the values of \\(t\\) for which the particle is at rest.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Substitute \\(t = 0\\), \\(v = 5\\).", workingLatex: "5 = k(0) - 12(0) + c \\implies c = 5", explanation: "" }, { stepNumber: 2, description: "Substitute \\(t = 2\\), \\(v = 1\\).", workingLatex: "1 = 4k - 24 + 5 \\implies 4k = 20 \\implies k = 5", explanation: "" }, { stepNumber: 3, description: "So \\(v = 5t^2 - 12t + 5\\).", workingLatex: "v = 5t^2 - 12t + 5", explanation: "" }, { stepNumber: 4, description: "(b) Differentiate to find acceleration.", workingLatex: "a = \\frac{\\mathrm{d}v}{\\mathrm{d}t} = 10t - 12", explanation: "" }, { stepNumber: 5, description: "Substitute \\(t = 3\\).", workingLatex: "a = 10(3) - 12 = 18", explanation: "" }, { stepNumber: 6, description: "(c) Set \\(v = 0\\).", workingLatex: "5t^2 - 12t + 5 = 0", explanation: "" }, { stepNumber: 7, description: "Apply the quadratic formula.", workingLatex: "t = \\frac{12 \\pm \\sqrt{144 - 100}}{10} = \\frac{12 \\pm \\sqrt{44}}{10} = \\frac{12 \\pm 2\\sqrt{11}}{10} = \\frac{6 \\pm \\sqrt{11}}{5}", explanation: "" }], finalAnswer: "(a) \\(k = 5\\), \\(c = 5\\). (b) \\(a = 18\\) m s\\(^{-2}\\). (c) \\(t = \\frac{6 - \\sqrt{11}}{5}\\) s and \\(t = \\frac{6 + \\sqrt{11}}{5}\\) s." } },
    { id: "y1k2-028", topicRef: "y1k2", topicTitle: "Variable Acceleration 28", yearCreated: 2026, examStyle: true, marks: 9, difficulty: "Standard", tags: ["unknown coefficients", "displacement", "conditions", "velocity", "acceleration"], questionText: "A particle moves along a straight line. At time \\(t\\) seconds, the displacement of the particle from a fixed point \\(O\\) is \\(s = at^3 + bt^2 + ct\\) metres, where \\(a\\), \\(b\\) and \\(c\\) are constants. When \\(t = 0\\) the velocity is \\(6\\) m s\\(^{-1}\\). When \\(t = 1\\) the velocity is \\(0\\). When \\(t = 2\\) the acceleration is \\(0\\). (a) Find the values of \\(a\\), \\(b\\) and \\(c\\). (b) Find the displacement of the particle when \\(t = 3\\).", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Differentiate to find velocity and acceleration.", workingLatex: "v = 3at^2 + 2bt + c, \\quad a_{\\text{acc}} = 6at + 2b", explanation: "" }, { stepNumber: 2, description: "Use \\(v(0) = 6\\).", workingLatex: "c = 6", explanation: "" }, { stepNumber: 3, description: "Use \\(v(1) = 0\\).", workingLatex: "3a + 2b + 6 = 0 \\quad \\cdots (1)", explanation: "" }, { stepNumber: 4, description: "Use acceleration \\(= 0\\) when \\(t = 2\\).", workingLatex: "12a + 2b = 0 \\implies b = -6a \\quad \\cdots (2)", explanation: "" }, { stepNumber: 5, description: "Substitute (2) into (1).", workingLatex: "3a + 2(-6a) + 6 = 0 \\implies 3a - 12a + 6 = 0 \\implies -9a = -6 \\implies a = \\frac{2}{3}", explanation: "" }, { stepNumber: 6, description: "Find \\(b\\).", workingLatex: "b = -6 \\times \\frac{2}{3} = -4", explanation: "" }, { stepNumber: 7, description: "(b) Find \\(s\\) when \\(t = 3\\).", workingLatex: "s = \\frac{2}{3}(27) - 4(9) + 6(3) = 18 - 36 + 18 = 0", explanation: "" }], finalAnswer: "(a) \\(a = \\frac{2}{3}\\), \\(b = -4\\), \\(c = 6\\). (b) \\(s = 0\\) m (the particle returns to \\(O\\))." } },
    { id: "y1k2-029", topicRef: "y1k2", topicTitle: "Variable Acceleration 29", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Standard", tags: ["maximum velocity", "acceleration zero", "differentiation"], questionText: "A particle moves along a straight line with velocity \\(v = 12t - 3t^2 + 1\\) m s\\(^{-1}\\) at time \\(t \\geq 0\\) seconds. Find the maximum velocity of the particle.", workedSolution: { steps: [{ stepNumber: 1, description: "The velocity is maximised when the acceleration is zero. Find the acceleration.", workingLatex: "a = \\frac{\\mathrm{d}v}{\\mathrm{d}t} = 12 - 6t", explanation: "" }, { stepNumber: 2, description: "Set \\(a = 0\\) and solve.", workingLatex: "12 - 6t = 0 \\implies t = 2", explanation: "" }, { stepNumber: 3, description: "Verify this is a maximum by checking the second derivative of \\(v\\).", workingLatex: "\\frac{\\mathrm{d}a}{\\mathrm{d}t} = -6 < 0", explanation: "Since the second derivative of \\(v\\) is negative, \\(t = 2\\) gives a maximum." }, { stepNumber: 4, description: "Substitute \\(t = 2\\) into the velocity.", workingLatex: "v = 12(2) - 3(4) + 1 = 24 - 12 + 1 = 13", explanation: "" }], finalAnswer: "The maximum velocity is \\(13\\) m s\\(^{-1}\\)." } },
    { id: "y1k2-030", topicRef: "y1k2", topicTitle: "Variable Acceleration 30", yearCreated: 2026, examStyle: true, marks: 8, difficulty: "Standard", tags: ["integration", "displacement", "velocity", "show that", "never returns"], questionText: "A particle starts from rest at the origin and moves along a straight line with acceleration \\(a = 2t + 4\\) m s\\(^{-2}\\) for \\(t \\geq 0\\). (a) Find expressions for the velocity and displacement at time \\(t\\). (b) Show that the particle never returns to its starting point.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Integrate to find velocity. Use \\(v = 0\\) when \\(t = 0\\).", workingLatex: "v = \\int (2t + 4)\\,\\mathrm{d}t = t^2 + 4t + c_1", explanation: "\\(c_1 = 0\\) since the particle starts from rest." }, { stepNumber: 2, description: "Integrate to find displacement. Use \\(s = 0\\) when \\(t = 0\\).", workingLatex: "s = \\int (t^2 + 4t)\\,\\mathrm{d}t = \\frac{t^3}{3} + 2t^2 + c_2", explanation: "\\(c_2 = 0\\) since the particle starts at the origin." }, { stepNumber: 3, description: "So \\(v = t^2 + 4t\\) and \\(s = \\frac{t^3}{3} + 2t^2\\).", workingLatex: "v = t^2 + 4t, \\quad s = \\frac{t^3}{3} + 2t^2", explanation: "" }, { stepNumber: 4, description: "(b) For the particle to return to the origin, we need \\(s = 0\\) for some \\(t > 0\\).", workingLatex: "\\frac{t^3}{3} + 2t^2 = 0 \\implies t^2\\left(\\frac{t}{3} + 2\\right) = 0", explanation: "" }, { stepNumber: 5, description: "Solve.", workingLatex: "t = 0 \\quad \\text{or} \\quad t = -6", explanation: "The only solutions are \\(t = 0\\) (the starting time) and \\(t = -6\\) (not valid since \\(t \\geq 0\\)). Therefore the particle never returns to its starting point." }], finalAnswer: "(a) \\(v = t^2 + 4t\\), \\(s = \\frac{t^3}{3} + 2t^2\\). (b) \\(s = 0\\) only when \\(t = 0\\) or \\(t = -6\\); since \\(t \\geq 0\\), the particle never returns." } },
    { id: "y1k2-031", topicRef: "y1k2", topicTitle: "Variable Acceleration 31", yearCreated: 2026, examStyle: true, marks: 9, difficulty: "Standard", tags: ["integration", "acceleration", "velocity", "displacement", "multi-part", "exam style"], questionText: "A particle \\(P\\) moves along a straight line. At time \\(t\\) seconds (\\(t \\geq 0\\)), the acceleration of \\(P\\) is \\(a = (8 - 4t)\\) m s\\(^{-2}\\). When \\(t = 0\\), \\(P\\) is at rest at the origin. (a) Find the velocity of \\(P\\) at time \\(t\\). (b) Find the maximum velocity of \\(P\\). (c) Find the displacement of \\(P\\) from the origin when the velocity is at its maximum.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Integrate to find velocity. Use \\(v = 0\\) when \\(t = 0\\).", workingLatex: "v = \\int (8 - 4t)\\,\\mathrm{d}t = 8t - 2t^2 + c_1", explanation: "\\(c_1 = 0\\) since \\(P\\) starts from rest." }, { stepNumber: 2, description: "So \\(v = 8t - 2t^2\\).", workingLatex: "v = 8t - 2t^2", explanation: "" }, { stepNumber: 3, description: "(b) Maximum velocity occurs when \\(a = 0\\).", workingLatex: "8 - 4t = 0 \\implies t = 2", explanation: "" }, { stepNumber: 4, description: "Check this is a maximum: \\(\\frac{\\mathrm{d}a}{\\mathrm{d}t} = -4 < 0\\), confirming a maximum.", workingLatex: "v_{\\max} = 8(2) - 2(4) = 16 - 8 = 8", explanation: "" }, { stepNumber: 5, description: "(c) Find the displacement at \\(t = 2\\). Integrate velocity, using \\(s = 0\\) when \\(t = 0\\).", workingLatex: "s = \\int (8t - 2t^2)\\,\\mathrm{d}t = 4t^2 - \\frac{2t^3}{3} + c_2", explanation: "\\(c_2 = 0\\) since the particle starts at the origin." }, { stepNumber: 6, description: "Substitute \\(t = 2\\).", workingLatex: "s = 4(4) - \\frac{2(8)}{3} = 16 - \\frac{16}{3} = \\frac{32}{3}", explanation: "" }], finalAnswer: "(a) \\(v = 8t - 2t^2\\). (b) Maximum velocity is \\(8\\) m s\\(^{-1}\\). (c) Displacement is \\(\\frac{32}{3}\\) m." } },
    { id: "y1k2-032", topicRef: "y1k2", topicTitle: "Variable Acceleration 32", yearCreated: 2026, examStyle: true, marks: 10, difficulty: "Standard", tags: ["unknown coefficients", "velocity", "displacement", "simultaneous equations", "multi-part"], questionText: "A particle \\(P\\) moves along a straight line. At time \\(t\\) seconds, the velocity of \\(P\\) is \\(v = At^2 + Bt + C\\) m s\\(^{-1}\\), where \\(A\\), \\(B\\) and \\(C\\) are constants. When \\(t = 0\\), \\(v = 10\\). When \\(t = 1\\), \\(v = 3\\). When \\(t = 3\\), \\(v = 1\\). (a) Find the values of \\(A\\), \\(B\\) and \\(C\\). (b) Find the times at which the particle is at rest. (c) Find the displacement of the particle from its initial position between \\(t = 0\\) and \\(t = 5\\).", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Use \\(v(0) = 10\\).", workingLatex: "C = 10", explanation: "" }, { stepNumber: 2, description: "Use \\(v(1) = 3\\).", workingLatex: "A + B + 10 = 3 \\implies A + B = -7 \\quad \\cdots (1)", explanation: "" }, { stepNumber: 3, description: "Use \\(v(3) = 1\\).", workingLatex: "9A + 3B + 10 = 1 \\implies 9A + 3B = -9 \\implies 3A + B = -3 \\quad \\cdots (2)", explanation: "" }, { stepNumber: 4, description: "Subtract (1) from (2).", workingLatex: "2A = 4 \\implies A = 2", explanation: "" }, { stepNumber: 5, description: "Substitute into (1).", workingLatex: "2 + B = -7 \\implies B = -9", explanation: "" }, { stepNumber: 6, description: "So \\(v = 2t^2 - 9t + 10\\).", workingLatex: "v = 2t^2 - 9t + 10", explanation: "" }, { stepNumber: 7, description: "(b) Set \\(v = 0\\).", workingLatex: "2t^2 - 9t + 10 = 0 \\implies (2t - 5)(t - 2) = 0 \\implies t = 2 \\text{ or } t = \\frac{5}{2}", explanation: "" }, { stepNumber: 8, description: "(c) Integrate velocity from \\(t = 0\\) to \\(t = 5\\).", workingLatex: "s = \\int_0^5 (2t^2 - 9t + 10)\\,\\mathrm{d}t = \\left[\\frac{2t^3}{3} - \\frac{9t^2}{2} + 10t\\right]_0^5", explanation: "" }, { stepNumber: 9, description: "Evaluate.", workingLatex: "s = \\frac{250}{3} - \\frac{225}{2} + 50 = \\frac{500 - 675 + 300}{6} = \\frac{125}{6}", explanation: "" }], finalAnswer: "(a) \\(A = 2\\), \\(B = -9\\), \\(C = 10\\). (b) The particle is at rest when \\(t = 2\\) s and \\(t = \\frac{5}{2}\\) s. (c) The displacement is \\(\\frac{125}{6}\\) m." } },
    { id: "y1k2-033", topicRef: "y1k2", topicTitle: "Variable Acceleration 33", yearCreated: 2026, examStyle: true, marks: 9, difficulty: "Challenge", tags: ["displacement function", "velocity", "acceleration", "never returns", "show that"], questionText: "A particle moves along a straight line with displacement \\(s = 2t^3 - 3t^2 + 6t\\) metres from a fixed point \\(O\\) at time \\(t \\geq 0\\) seconds. (a) Show that the velocity of the particle is always positive. (b) Find the minimum velocity of the particle. (c) Hence explain why the particle never returns to \\(O\\).", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Find the velocity.", workingLatex: "v = \\frac{\\mathrm{d}s}{\\mathrm{d}t} = 6t^2 - 6t + 6", explanation: "" }, { stepNumber: 2, description: "Show this is always positive by completing the square.", workingLatex: "v = 6(t^2 - t + 1) = 6\\left(\\left(t - \\frac{1}{2}\\right)^2 + \\frac{3}{4}\\right)", explanation: "" }, { stepNumber: 3, description: "Since \\((t - \\frac{1}{2})^2 \\geq 0\\), we have \\(v \\geq 6 \\times \\frac{3}{4} = \\frac{9}{2} > 0\\) for all \\(t\\).", workingLatex: "v \\geq \\frac{9}{2} > 0 \\text{ for all } t", explanation: "The velocity is always positive." }, { stepNumber: 4, description: "(b) The minimum velocity occurs at the vertex of the completed square, when \\(t = \\frac{1}{2}\\).", workingLatex: "v_{\\min} = 6 \\times \\frac{3}{4} = \\frac{9}{2}", explanation: "" }, { stepNumber: 5, description: "(c) Since \\(s(0) = 0\\) and the velocity is always positive, the particle always moves in the positive direction away from \\(O\\).", workingLatex: "\\text{Since } v > 0 \\text{ for all } t \\geq 0, \\text{ the displacement } s \\text{ is strictly increasing, so the particle never returns to } O.", explanation: "" }], finalAnswer: "(a) \\(v = 6(t - \\frac{1}{2})^2 + \\frac{9}{2} > 0\\) for all \\(t\\). (b) Minimum velocity is \\(\\frac{9}{2}\\) m s\\(^{-1}\\) at \\(t = \\frac{1}{2}\\). (c) Since velocity is always positive the particle moves away from \\(O\\) and never returns." } },
    { id: "y1k2-034", topicRef: "y1k2", topicTitle: "Variable Acceleration 34", yearCreated: 2026, examStyle: true, marks: 10, difficulty: "Challenge", tags: ["integration", "acceleration", "velocity", "displacement", "distance", "direction change", "multi-part"], questionText: "A particle starts from rest at a point \\(O\\) and moves along a straight line. The acceleration of the particle at time \\(t\\) seconds is \\(a = (6 - 3t)\\) m s\\(^{-2}\\). (a) Find the velocity of the particle at time \\(t\\). (b) Find the time at which the particle is next at rest. (c) Find the maximum displacement from \\(O\\). (d) Find the displacement of the particle from \\(O\\) when \\(t = 6\\).", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Integrate to find velocity. Use \\(v = 0\\) when \\(t = 0\\).", workingLatex: "v = \\int (6 - 3t)\\,\\mathrm{d}t = 6t - \\frac{3t^2}{2} + c_1", explanation: "\\(c_1 = 0\\) since the particle starts from rest." }, { stepNumber: 2, description: "So \\(v = 6t - \\frac{3t^2}{2}\\).", workingLatex: "v = 6t - \\frac{3t^2}{2}", explanation: "" }, { stepNumber: 3, description: "(b) Set \\(v = 0\\) for \\(t > 0\\).", workingLatex: "6t - \\frac{3t^2}{2} = 0 \\implies t\\left(6 - \\frac{3t}{2}\\right) = 0 \\implies t = 0 \\text{ or } t = 4", explanation: "The particle is next at rest when \\(t = 4\\)." }, { stepNumber: 4, description: "(c) The maximum displacement occurs when the velocity changes from positive to negative, i.e., at \\(t = 4\\). Find \\(s\\) by integrating velocity, using \\(s = 0\\) when \\(t = 0\\).", workingLatex: "s = \\int \\left(6t - \\frac{3t^2}{2}\\right)\\mathrm{d}t = 3t^2 - \\frac{t^3}{2} + c_2", explanation: "\\(c_2 = 0\\)." }, { stepNumber: 5, description: "Substitute \\(t = 4\\).", workingLatex: "s = 3(16) - \\frac{64}{2} = 48 - 32 = 16", explanation: "" }, { stepNumber: 6, description: "(d) Substitute \\(t = 6\\).", workingLatex: "s = 3(36) - \\frac{216}{2} = 108 - 108 = 0", explanation: "The particle has returned to \\(O\\)." }], finalAnswer: "(a) \\(v = 6t - \\frac{3t^2}{2}\\). (b) Next at rest when \\(t = 4\\) s. (c) Maximum displacement is \\(16\\) m. (d) When \\(t = 6\\), \\(s = 0\\) m (particle is back at \\(O\\))." } },
    { id: "y1k2-035", topicRef: "y1k2", topicTitle: "Variable Acceleration 35", yearCreated: 2026, examStyle: true, marks: 11, difficulty: "Challenge", tags: ["show that", "algebraic proof", "velocity", "displacement", "integration"], questionText: "A particle has velocity \\(v = At^2 + Bt\\) m s\\(^{-1}\\) at time \\(t \\geq 0\\) seconds, where \\(A\\) and \\(B\\) are non-zero constants with \\(A\\) and \\(B\\) having opposite signs. The particle starts from the origin. (a) Show that the particle returns to the origin at time \\(T = -\\dfrac{3B}{2A}\\). (b) Show that this time \\(T\\) is positive. (c) Find, in terms of \\(A\\) and \\(B\\), the maximum displacement of the particle from the origin.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Integrate velocity to find displacement, using \\(s = 0\\) when \\(t = 0\\).", workingLatex: "s = \\int (At^2 + Bt)\\,\\mathrm{d}t = \\frac{At^3}{3} + \\frac{Bt^2}{2} + c", explanation: "\\(c = 0\\) since the particle starts at the origin." }, { stepNumber: 2, description: "Set \\(s = 0\\) for the particle to return to the origin.", workingLatex: "\\frac{At^3}{3} + \\frac{Bt^2}{2} = 0 \\implies t^2\\left(\\frac{At}{3} + \\frac{B}{2}\\right) = 0", explanation: "" }, { stepNumber: 3, description: "Solve for \\(t > 0\\).", workingLatex: "\\frac{At}{3} + \\frac{B}{2} = 0 \\implies t = -\\frac{3B}{2A} = T \\quad \\text{as required.}", explanation: "\\(t = 0\\) is the initial time and is excluded." }, { stepNumber: 4, description: "(b) Since \\(A\\) and \\(B\\) have opposite signs, \\(-B/A > 0\\), so \\(T = \\frac{3}{2} \\times (-B/A) > 0\\).", workingLatex: "A \\text{ and } B \\text{ have opposite signs} \\implies -\\frac{B}{A} > 0 \\implies T = -\\frac{3B}{2A} > 0", explanation: "" }, { stepNumber: 5, description: "(c) The velocity is zero (other than at \\(t = 0\\)) when \\(At^2 + Bt = 0\\), i.e., \\(t(At + B) = 0\\), giving \\(t = -B/A\\).", workingLatex: "t^* = -\\frac{B}{A}", explanation: "This is positive (since \\(A\\) and \\(B\\) have opposite signs) and is the time of maximum displacement." }, { stepNumber: 6, description: "Find the displacement at \\(t^* = -B/A\\).", workingLatex: "s^* = \\frac{A}{3}\\left(-\\frac{B}{A}\\right)^3 + \\frac{B}{2}\\left(-\\frac{B}{A}\\right)^2 = -\\frac{B^3}{3A^2} + \\frac{B^3}{2A^2} = \\frac{B^3}{A^2}\\left(-\\frac{1}{3} + \\frac{1}{2}\\right) = \\frac{B^3}{6A^2}", explanation: "" }], finalAnswer: "(a) The particle returns to the origin when \\(T = -\\frac{3B}{2A}\\) as required. (b) Since \\(A\\) and \\(B\\) have opposite signs, \\(T > 0\\). (c) Maximum displacement is \\(\\frac{B^3}{6A^2}\\)." } },
    { id: "y1k2-036", topicRef: "y1k2", topicTitle: "Variable Acceleration 36", yearCreated: 2026, examStyle: true, marks: 11, difficulty: "Challenge", tags: ["distance", "displacement", "direction change", "integration", "split integral"], questionText: "A particle has acceleration \\(a = 6 - 2t\\) m s\\(^{-2}\\) at time \\(t\\) seconds. The particle starts from rest. (a) Find the velocity at time \\(t\\). (b) Find the times when the particle is at rest. (c) Find the total distance travelled by the particle in the first \\(9\\) seconds.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Integrate to find velocity. Use \\(v = 0\\) when \\(t = 0\\).", workingLatex: "v = \\int (6 - 2t)\\,\\mathrm{d}t = 6t - t^2 + c_1", explanation: "\\(c_1 = 0\\)." }, { stepNumber: 2, description: "So \\(v = 6t - t^2 = t(6 - t)\\).", workingLatex: "v = 6t - t^2", explanation: "" }, { stepNumber: 3, description: "(b) Set \\(v = 0\\).", workingLatex: "t(6 - t) = 0 \\implies t = 0 \\text{ or } t = 6", explanation: "" }, { stepNumber: 4, description: "(c) Find displacement. Use \\(s = 0\\) when \\(t = 0\\).", workingLatex: "s = \\int (6t - t^2)\\,\\mathrm{d}t = 3t^2 - \\frac{t^3}{3} + c_2", explanation: "\\(c_2 = 0\\)." }, { stepNumber: 5, description: "For \\(0 \\leq t \\leq 6\\), \\(v \\geq 0\\), so the particle moves in the positive direction. Distance from \\(t = 0\\) to \\(t = 6\\):", workingLatex: "s(6) = 3(36) - \\frac{216}{3} = 108 - 72 = 36", explanation: "" }, { stepNumber: 6, description: "For \\(6 < t \\leq 9\\), \\(v < 0\\), so the particle reverses. Distance from \\(t = 6\\) to \\(t = 9\\):", workingLatex: "s(9) = 3(81) - \\frac{729}{3} = 243 - 243 = 0", explanation: "" }, { stepNumber: 7, description: "So the distance in the backwards phase is:", workingLatex: "|s(9) - s(6)| = |0 - 36| = 36", explanation: "" }, { stepNumber: 8, description: "Total distance.", workingLatex: "\\text{Total distance} = 36 + 36 = 72", explanation: "" }], finalAnswer: "(a) \\(v = 6t - t^2\\). (b) At rest when \\(t = 0\\) s and \\(t = 6\\) s. (c) Total distance in the first 9 seconds is \\(72\\) m." } },
    { id: "y1k2-037", topicRef: "y1k2", topicTitle: "Variable Acceleration 37", yearCreated: 2026, examStyle: true, marks: 12, difficulty: "Challenge", tags: ["two particles", "velocity", "same velocity", "same displacement", "calculus"], questionText: "Particles \\(A\\) and \\(B\\) move along a straight line. At time \\(t = 0\\), both particles are at the origin. The velocity of \\(A\\) at time \\(t\\) seconds is \\(v_A = 6t - t^2\\) m s\\(^{-1}\\) and the velocity of \\(B\\) is \\(v_B = 3t\\) m s\\(^{-1}\\). (a) Find the time \\(t > 0\\) at which \\(A\\) and \\(B\\) have the same velocity. (b) Find the time \\(t > 0\\) at which \\(A\\) and \\(B\\) have the same displacement from the origin.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Set \\(v_A = v_B\\).", workingLatex: "6t - t^2 = 3t \\implies 3t - t^2 = 0 \\implies t(3 - t) = 0", explanation: "" }, { stepNumber: 2, description: "For \\(t > 0\\).", workingLatex: "t = 3", explanation: "" }, { stepNumber: 3, description: "(b) Find displacement of \\(A\\). Both start at origin so constants are zero.", workingLatex: "s_A = \\int (6t - t^2)\\,\\mathrm{d}t = 3t^2 - \\frac{t^3}{3}", explanation: "" }, { stepNumber: 4, description: "Find displacement of \\(B\\).", workingLatex: "s_B = \\int 3t\\,\\mathrm{d}t = \\frac{3t^2}{2}", explanation: "" }, { stepNumber: 5, description: "Set \\(s_A = s_B\\) for \\(t > 0\\).", workingLatex: "3t^2 - \\frac{t^3}{3} = \\frac{3t^2}{2}", explanation: "" }, { stepNumber: 6, description: "Rearrange (divide by \\(t^2\\) since \\(t > 0\\)).", workingLatex: "3 - \\frac{t}{3} = \\frac{3}{2} \\implies \\frac{t}{3} = \\frac{3}{2} \\implies t = \\frac{9}{2}", explanation: "" }], finalAnswer: "(a) The particles have the same velocity when \\(t = 3\\) s. (b) The particles have the same displacement when \\(t = \\frac{9}{2}\\) s." } },
    { id: "y1k2-038", topicRef: "y1k2", topicTitle: "Variable Acceleration 38", yearCreated: 2026, examStyle: true, marks: 12, difficulty: "Challenge", tags: ["show that", "speed", "symmetry", "velocity", "algebraic proof"], questionText: "A particle moves along a straight line with velocity \\(v = pt^2 - qt\\) m s\\(^{-1}\\) at time \\(t \\geq 0\\) seconds, where \\(p\\) and \\(q\\) are positive constants. (a) Find the times at which the speed of the particle is zero. (b) Given that the speed of the particle is the same at times \\(t_1\\) and \\(t_2\\) where \\(0 < t_1 < t_2\\), show that \\(t_1 + t_2 = \\dfrac{q}{p}\\).", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Set \\(v = 0\\).", workingLatex: "pt^2 - qt = 0 \\implies t(pt - q) = 0 \\implies t = 0 \\text{ or } t = \\frac{q}{p}", explanation: "" }, { stepNumber: 2, description: "(b) If the speed is the same at \\(t_1\\) and \\(t_2\\), then \\(|v(t_1)| = |v(t_2)|\\). This means either \\(v(t_1) = v(t_2)\\) or \\(v(t_1) = -v(t_2)\\). Since the velocity is a quadratic with the same sign on each side of a root, for \\(t_1 \\neq t_2\\) the case \\(v(t_1) = v(t_2)\\) applies.", workingLatex: "pt_1^2 - qt_1 = pt_2^2 - qt_2", explanation: "" }, { stepNumber: 3, description: "Rearrange.", workingLatex: "p(t_1^2 - t_2^2) = q(t_1 - t_2) \\implies p(t_1 + t_2)(t_1 - t_2) = q(t_1 - t_2)", explanation: "" }, { stepNumber: 4, description: "Since \\(t_1 \\neq t_2\\), divide by \\((t_1 - t_2)\\).", workingLatex: "p(t_1 + t_2) = q \\implies t_1 + t_2 = \\frac{q}{p} \\quad \\text{as required.}", explanation: "This result follows from the symmetry of the parabola \\(v = p(t - q/(2p))^2 - q^2/(4p)\\) about \\(t = q/(2p)\\)." }], finalAnswer: "(a) Speed is zero when \\(t = 0\\) and \\(t = \\frac{q}{p}\\). (b) Since \\(v(t_1) = v(t_2)\\) with \\(t_1 \\neq t_2\\), factoring gives \\(t_1 + t_2 = \\frac{q}{p}\\) as required." } },
    { id: "y1k2-039", topicRef: "y1k2", topicTitle: "Variable Acceleration 39", yearCreated: 2026, examStyle: true, marks: 13, difficulty: "Challenge", tags: ["two particles", "calculus", "velocity", "displacement", "overtaking", "multi-part"], questionText: "Particle \\(A\\) starts from rest at the origin and moves with constant acceleration \\(4\\) m s\\(^{-2}\\). At the same instant, particle \\(B\\) passes through the origin with velocity \\(20\\) m s\\(^{-1}\\) and acceleration \\(a_B = -2t\\) m s\\(^{-2}\\). (a) Find expressions for the velocities \\(v_A\\) and \\(v_B\\) at time \\(t\\). (b) Find the time at which the velocities are equal. (c) Find expressions for the displacements \\(s_A\\) and \\(s_B\\) from the origin at time \\(t\\). (d) Find the time \\(t > 0\\) at which the particles are at the same point.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) For \\(A\\): constant acceleration, starts from rest.", workingLatex: "v_A = 4t", explanation: "" }, { stepNumber: 2, description: "For \\(B\\): integrate \\(a_B = -2t\\) with \\(v_B(0) = 20\\).", workingLatex: "v_B = \\int (-2t)\\,\\mathrm{d}t = -t^2 + c_1", explanation: "\\(c_1 = 20\\), so \\(v_B = 20 - t^2\\)." }, { stepNumber: 3, description: "(b) Set \\(v_A = v_B\\).", workingLatex: "4t = 20 - t^2 \\implies t^2 + 4t - 20 = 0", explanation: "" }, { stepNumber: 4, description: "Solve using the quadratic formula.", workingLatex: "t = \\frac{-4 + \\sqrt{16 + 80}}{2} = \\frac{-4 + \\sqrt{96}}{2} = \\frac{-4 + 4\\sqrt{6}}{2} = -2 + 2\\sqrt{6}", explanation: "Reject the negative root." }, { stepNumber: 5, description: "(c) Displacements (both start at origin).", workingLatex: "s_A = \\int 4t\\,\\mathrm{d}t = 2t^2", explanation: "" }, { stepNumber: 6, description: "For \\(B\\):", workingLatex: "s_B = \\int (20 - t^2)\\,\\mathrm{d}t = 20t - \\frac{t^3}{3}", explanation: "Constant is zero since \\(B\\) starts at the origin." }, { stepNumber: 7, description: "(d) Set \\(s_A = s_B\\) for \\(t > 0\\).", workingLatex: "2t^2 = 20t - \\frac{t^3}{3}", explanation: "" }, { stepNumber: 8, description: "Multiply through by 3.", workingLatex: "6t^2 = 60t - t^3 \\implies t^3 + 6t^2 - 60t = 0 \\implies t(t^2 + 6t - 60) = 0", explanation: "" }, { stepNumber: 9, description: "For \\(t > 0\\), solve \\(t^2 + 6t - 60 = 0\\).", workingLatex: "t = \\frac{-6 + \\sqrt{36 + 240}}{2} = \\frac{-6 + \\sqrt{276}}{2} = \\frac{-6 + 2\\sqrt{69}}{2} = -3 + \\sqrt{69}", explanation: "" }], finalAnswer: "(a) \\(v_A = 4t\\), \\(v_B = 20 - t^2\\). (b) Velocities are equal when \\(t = -2 + 2\\sqrt{6} \\approx 2.90\\) s. (c) \\(s_A = 2t^2\\), \\(s_B = 20t - \\frac{t^3}{3}\\). (d) Particles meet at \\(t = -3 + \\sqrt{69} \\approx 5.31\\) s." } },
    { id: "y1k2-040", topicRef: "y1k2", topicTitle: "Variable Acceleration 40", yearCreated: 2026, examStyle: true, marks: 14, difficulty: "Challenge", tags: ["distance", "displacement", "direction change", "show that", "multi-part", "integration"], questionText: "A particle \\(P\\) moves along a straight line. At time \\(t = 0\\), \\(P\\) is at a point \\(O\\) with velocity \\(12\\) m s\\(^{-1}\\). The acceleration of \\(P\\) at time \\(t\\) seconds is \\(a = (4 - 2t)\\) m s\\(^{-2}\\). (a) Show that the velocity of \\(P\\) at time \\(t\\) is \\(v = 12 + 4t - t^2\\). (b) Find the maximum velocity of \\(P\\). (c) Show that \\(P\\) is at rest when \\(t = 6\\). (d) Find the total distance travelled by \\(P\\) between \\(t = 0\\) and \\(t = 8\\).", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Integrate to find velocity. Use \\(v = 12\\) when \\(t = 0\\).", workingLatex: "v = \\int (4 - 2t)\\,\\mathrm{d}t = 4t - t^2 + c", explanation: "" }, { stepNumber: 2, description: "Apply initial condition.", workingLatex: "12 = 0 - 0 + c \\implies c = 12 \\quad \\Rightarrow \\quad v = 12 + 4t - t^2 \\quad \\text{as required.}", explanation: "" }, { stepNumber: 3, description: "(b) Maximum velocity when \\(a = 0\\).", workingLatex: "4 - 2t = 0 \\implies t = 2", explanation: "" }, { stepNumber: 4, description: "Check: \\(\\frac{\\mathrm{d}a}{\\mathrm{d}t} = -2 < 0\\), confirming maximum. Substitute.", workingLatex: "v_{\\max} = 12 + 8 - 4 = 16", explanation: "" }, { stepNumber: 5, description: "(c) Substitute \\(t = 6\\) into the velocity.", workingLatex: "v = 12 + 24 - 36 = 0 \\quad \\text{as required.}", explanation: "" }, { stepNumber: 6, description: "(d) Find displacement. Integrate velocity using \\(s = 0\\) when \\(t = 0\\).", workingLatex: "s = \\int (12 + 4t - t^2)\\,\\mathrm{d}t = 12t + 2t^2 - \\frac{t^3}{3} + c_2", explanation: "\\(c_2 = 0\\)." }, { stepNumber: 7, description: "For \\(0 \\leq t \\leq 6\\), \\(v \\geq 0\\) since \\(v = -(t^2 - 4t - 12) = -(t - 6)(t + 2) \\geq 0\\) for \\(0 \\leq t \\leq 6\\). Distance from \\(t = 0\\) to \\(t = 6\\):", workingLatex: "s(6) = 72 + 72 - 72 = 72", explanation: "" }, { stepNumber: 8, description: "For \\(6 < t \\leq 8\\), \\(v < 0\\), so the particle moves backwards. Find \\(s(8)\\).", workingLatex: "s(8) = 96 + 128 - \\frac{512}{3} = 224 - \\frac{512}{3} = \\frac{672 - 512}{3} = \\frac{160}{3}", explanation: "" }, { stepNumber: 9, description: "Distance in the backwards phase.", workingLatex: "|s(8) - s(6)| = \\left|\\frac{160}{3} - 72\\right| = \\left|\\frac{160 - 216}{3}\\right| = \\frac{56}{3}", explanation: "" }, { stepNumber: 10, description: "Total distance.", workingLatex: "\\text{Total distance} = 72 + \\frac{56}{3} = \\frac{216 + 56}{3} = \\frac{272}{3}", explanation: "" }], finalAnswer: "(a) \\(v = 12 + 4t - t^2\\) as required. (b) Maximum velocity is \\(16\\) m s\\(^{-1}\\). (c) \\(v(6) = 0\\) as required. (d) Total distance is \\(\\frac{272}{3}\\) m, or \\(90\\frac{2}{3}\\) m." } },
];
